1	export type Item = {
2	  kind: "sword" | "amulet" | "staff" | "potion" | "rune" | "moonstone";
3	  cursed?: boolean;
4	  enchantment?: number;
5	};
6	
7	export type QuoteStep = { kind: "quote"; items: Item[] };
8	
9	export type Scenario = {
10	  customer: { yearsWithMHPCO: number };
11	  steps: QuoteStep[];
12	};
13	
14	export type ScenarioResult = {
15	  results: unknown[];
16	};
17	
18	const COMPONENT_BASE_PREMIUM = 25;
19	
20	const BASE_PREMIUM_BY_ITEM: Record<Item["kind"], number> = {
21	  sword: 100,
22	  amulet: 60,
23	  staff: 80,
24	  potion: 40,
25	  rune: COMPONENT_BASE_PREMIUM,
26	  moonstone: COMPONENT_BASE_PREMIUM,
27	};
28	
29	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
30	const PROCESSING_FEE = 5;
31	
32	const CURSED_SURCHARGE_RATE = 0.5;
33	
34	function riskMultiplierForItem(item: Item): number {
35	  return 1 + (item.cursed ? CURSED_SURCHARGE_RATE : 0);
36	}
37	
38	function basePremiumForItem(item: Item): number {
39	  return BASE_PREMIUM_BY_ITEM[item.kind] * riskMultiplierForItem(item);
40	}
41	
42	type QuoteResult = { kind: "quote"; premium: number };
43	
44	const BUILDING_BLOCK_BASE_PREMIUM = 60;
45	const BUILDING_BLOCK_SIZE = 3;
46	const COMPONENT_KINDS: ReadonlyArray<Item["kind"]> = ["rune", "moonstone"];
47	
48	type ItemGroup = { kind: Item["kind"]; items: Item[] };
49	
50	function groupByKind(items: Item[]): ItemGroup[] {
51	  const groups = new Map<Item["kind"], Item[]>();
52	  for (const item of items) {
53	    const group = groups.get(item.kind) ?? [];
54	    group.push(item);
55	    groups.set(item.kind, group);
56	  }
57	  return Array.from(groups, ([kind, items]) => ({ kind, items }));
58	}
59	
60	function isBuildingBlock(group: ItemGroup): boolean {
61	  return group.items.length === BUILDING_BLOCK_SIZE && COMPONENT_KINDS.includes(group.kind);
62	}
63	
64	function basePremiumForGroup(group: ItemGroup): number {
65	  if (isBuildingBlock(group)) {
66	    return BUILDING_BLOCK_BASE_PREMIUM;
67	  }
68	  return group.items.reduce((sum, item) => sum + basePremiumForItem(item), 0);
69	}
70	
71	function basePremiumForItems(items: Item[]): number {
72	  return groupByKind(items).reduce((sum, group) => sum + basePremiumForGroup(group), 0);
73	}
74	
75	function quoteStep(step: QuoteStep): QuoteResult {
76	  const basePremium = basePremiumForItems(step.items);
77	  const surcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
78	  const premium = Math.ceil(basePremium + surcharge + PROCESSING_FEE);
79	  return { kind: "quote", premium };
80	}
81	
82	export function processScenario(scenario: Scenario): ScenarioResult {
83	  const results = scenario.steps.map(quoteStep);
84	  return { results };
85	}
